mapper.select:
select samm.id as rowId,samm.meeting_code as meetingCode, samm.meeting_name as meetingName,samm.meeting_date as meetingDate, samm.meeting_end_date as meetingEndDate,csu.name as participantsName,samm.speech_topic as speechTopic, samm.meeting_place as meetingPlace,samm.participants,samm.is_speech as isSpeech,samm.meeting_phone as meetingPhone,samm.meeting_email as meetingEmail ,samm.dept_id as deptId,csd.name as deptName ,samm.proj_id as projId,spi.name as projName ,samm.note,samm.data_status as dataStatus,samm.sys_no as sysNo,samm.trvl_begin_date as trvlBeginDate,samm.trvl_end_date as trvlEndDate ,samm.meeting_type,csct.name as meetingTypeName,samm.expected_begin_date as expectedBeginDate ,samm.create_date,csu1.name as creatorName,csu2.name as subUserName,samm.sub_date from srm_ac_meeting_manage samm left join srm_projects_info spi on samm.proj_id=spi.id left join ct_srm_dept csd on samm.dept_id=csd.id left join ct_srm_conference_type csct on samm.meeting_type =csct.code left join ct_srm_user csu on samm.participants=csu.id left join ct_srm_user csu1 on samm.create_user_id=csu1.id left join ct_srm_user csu2 on samm.sub_user_id=csu2.id
and samm.data_status=#{acMeetingManageDto.dataStatus}
and (samm.meeting_name LIKE CONCAT('%', #{acMeetingManageDto.meetingName}, '%') or samm.meeting_place LIKE CONCAT('%', #{acMeetingManageDto.meetingName}, '%'))
and samm.meeting_date = #{acMeetingManageDto.meetingDate}
order by samm.id desc
